#include <iostream>
#include <string_view>

enum Mode
{
    off,
    on,
    autoMode,
};

std::string_view modeName(Mode m)
{
    switch (m)
    {
        case off:      return "off";
        case on:       return "on";
        case autoMode: return "auto";
    }
    return "?";
}

int main()
{
    Mode m { autoMode };
    std::cout << modeName(m) << '\n';
    return 0;
}
