```cpp
#include <iostream>
#include <string>
#include <string_view>

enum Pet
{
    cat,
    dog,
    fish,
    none,
};

Pet petFromName(std::string_view name)
{
    if (name == "cat")  return cat;
    if (name == "dog")  return dog;
    if (name == "fish") return fish;
    return none;
}

int main()
{
    std::string s { "dog" };
    Pet p { petFromName(s) };
    std::cout << p << '\n';
    return 0;
}
```
